<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">properties.additional</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=\${module_path}/src/main/resources/application.properties</span></span>
